const dotenv = require\('dotenv'\); dotenv.config\(\);
const { connectDB } = require\('./config/db.js'\); connectDB\(\);
const userModel = require\('./models/userModel.js'\);

const checkBloodCompatibility = \(donorType, requestedType\) => {
  const compatibility = {
    'O-': ['O-','O+','A-','A+','B-','B+','AB-','AB+'],
    'O+': ['O+','A+','B+','AB+'],
    'A-': ['A-','A+','AB-','AB+'], 'A+': ['A+','AB+'],
    'B-': ['B-','B+','AB-','AB+'], 'B+': ['B+','AB+'],
    'AB-': ['AB-','AB+'], 'AB+': ['AB+']
  };
  return compatibility[donorType]?.includes\(requestedType\) || false;
};

\(async \(\) => {
  const allDonors = await userModel.find\({ role: 'donar' }\).select\(
    'name email phone bloodGroup address location lastDonation totalDonations'
  \);
  console.log\('Total donors:', allDonors.length\);

  const bloodType = 'O+';
  for \(const d of allDonors\) {
    if \(!d.location || \(!d.location.lat && !d.location.lng\)\) {
      d.location = { lat: 28.5 + Math.random\(\)*0.3, lng: 77.0 + Math.random\(\)*0.4 };
    }
    const compat = checkBloodCompatibility\(d.bloodGroup, bloodType\);
    if \(compat\) {
      console.log\('Compatible:', d.name, d.bloodGroup, 'loc:', d.location, '_doc keys:', Object.keys\(d._doc || {}\)\);
    }
  }
}\)\(\);
")
